1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("Claim Office - quote (premium)", () => {
5	  // Fee-only baseline
6	  it("should charge 5 G (fee only) for an empty item list", () => {
7	    expect(quote([], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(5);
8	  });
9	
10	  // Single main item base premiums + fee
11	  it("should quote a single sword at 105 G (100 base + 5 fee)", () => {
12	    expect(quote([{ type: "sword" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(105);
13	  });
14	  it("should quote a single amulet at 65 G (60 base + 5 fee)", () => {
15	    expect(quote([{ type: "amulet" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(65);
16	  });
17	  it("should quote a single staff at 85 G (80 base + 5 fee)", () => {
18	    expect(quote([{ type: "staff" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(85);
19	  });
20	  it("should quote a single potion at 45 G (40 base + 5 fee)", () => {
21	    expect(quote([{ type: "potion" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(45);
22	  });
23	
24	  // Multiple main items sum their base premiums
25	  it("should sum base premiums for a sword and an amulet to 165 G (160 base + 5 fee)", () => {
26	    expect(quote([{ type: "sword" }, { type: "amulet" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(165);
27	  });
28	
29	  // Component base premiums
30	  it("should quote a single rune at 30 G (25 base + 5 fee)", () => {
31	    expect(quote([{ type: "rune" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(30);
32	  });
33	  it("should quote 2 runes at 55 G (50 base + 5 fee)", () => {
34	    expect(quote([{ type: "rune" }, { type: "rune" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(55);
35	  });
36	
37	  // Building block of 3 alike components
38	  it("should quote 3 runes as a block at 65 G (60 base + 5 fee)", () => {
39	    expect(quote([{ type: "rune" }, { type: "rune" }, { type: "rune" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(65);
40	  });
41	  it("should quote 4 runes at 105 G (no block, 100 base + 5 fee)", () => {
42	    expect(
43	      quote([{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }], { yearsWithMHPCO: 0, isFollowUp: false })
44	    ).toBe(105);
45	  });
46	  it.todo("should quote 7 runes at 180 G (175 base + 5 fee)");
47	
48	  // Alike = same type only
49	  it.todo("should not form a block for 2 runes + 1 moonstone (75 base + 5 fee = 80 G)");
50	  it.todo("should form two separate blocks for 3 runes + 3 moonstones (120 base + 5 fee = 125 G)");
51	
52	  // Item-specific modifiers
53	  it.todo("should add 50% curse surcharge to the cursed item's base premium");
54	  it.todo("should add 30% high-enchantment surcharge for enchantment >= 5");
55	  it.todo("should not add high-enchantment surcharge for enchantment 4");
56	  it.todo("should apply both curse and high-enchantment surcharges to a cursed enchantment-5 item");
57	
58	  // Modifier scope on multi-item policies
59	  it.todo("should apply the curse surcharge only to the cursed item, not the whole policy (cursed sword + plain amulet = 210 base before fee)");
60	
61	  // Policy-wide modifiers
62	  it.todo("should apply 20% loyalty discount for a customer with exactly 2 years");
63	  it.todo("should apply 10% first-insurance surcharge to the policy base premium");
64	  it.todo("should apply 15% follow-up discount on quotes after the customer's first quote");
65	
66	  // Rounding up in MHPCO's favor
67	  it.todo("should round the final premium up (197.5 G becomes 198 G)");
68	
69	  // Integration examples
70	  it.todo("should quote a newcomer's cursed steel sword (enchantment 3) at 165 G");
71	  it.todo("should quote a 3-year customer's second-quote cursed steel sword (enchantment 7) at 160 G");
72	
73	  // Error case
74	  it.todo("should reject a quote containing an item with an unknown type");
75	});
76	
77	describe("Claim Office - claim (payout)", () => {
78	  // Standard reimbursement minus deductible
79	  it.todo("should pay full damage minus 100 G deductible for a regular item (sword, enchantment 3, damage 500 -> 400)");
80	  it.todo("should pay full damage minus 100 G deductible for a component (rune, damage 200 -> 100)");
81	
82	  // High-enchantment clause
83	  it.todo("should reimburse 50% then deduct 100 G for enchantment >= 8 (steel sword, enchantment 9, damage 1000 -> 400)");
84	
85	  // Dragon-material clause
86	  it.todo("should fully reimburse then deduct 100 G for dragon material (dragon sword, enchantment 5, damage 800 -> 700)");
87	
88	  // Conflict: 50% rule wins over dragon
89	  it.todo("should apply the 50% rule (not full) when both high-enchantment >= 8 and dragon apply (dragon sword, enchantment 9, damage 1000 -> 400)");
90	
91	  // Threshold confirmation
92	  it.todo("should treat enchantment exactly 8 as high-enchantment (dragon sword, enchantment 8, damage 1000 -> 400)");
93	
94	  // Deductible per damage event
95	  it.todo("should apply the 100 G deductible once per damaged item (sword 500 + amulet 300 -> 600)");
96	
97	  // Cap behaviour
98	  it.todo("should cap total payout at twice the insurance sum");
99	  it.todo("should share the cap across successive claims and reduce payout to the remaining cap");
100	
101	  // Rounding down in MHPCO's favor
102	  it.todo("should round the final payout down (350.5 G becomes 350 G)");
103	
104	  // Error cases
105	  it.todo("should reject a claim whose damage entry references an item not in the policy");
106	  it.todo("should reject a claim with more damage entries of a type than the policy covers");
107	  it.todo("should reject a claim with a negative damage amount");
108	});
